{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires identifying a logical error in a step-by-step stack-based bracket matching derivation. Since the specific sequence and derivation steps were not provided in the prompt, the helpers are tasked with simulating the stack process and verifying the validity of each step.",
  "helpers": [
    {
      "label": "stack_simulator",
      "instructions": "Given the input sequence of brackets, simulate the stack-based matching process step by step. For each character in the sequence, record the current state of the stack and whether the character is an opening bracket (pushed) or a closing bracket (checked against the top of the stack). Output a table of steps showing: Step Number, Character Processed, Action Taken, and Resulting Stack State."
    },
    {
      "label": "error_detector",
      "instructions": "Compare the provided derivation steps from the problem description against the ground-truth stack simulation. Identify the exact step number where the derivation's reported stack state or action deviates from the correct stack-based algorithm. If the derivation claims a match that is incorrect or a mismatch that is incorrect, flag the specific index."
    }
  ],
  "synthesis_brief": "The parent agent will take the ground-truth simulation from the stack_simulator and compare it with the provided derivation using the error_detector. The first point of divergence identified by the error_detector will be the final answer."
}

